class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string s;
        while (a > 0 || b > 0) {
            if (a > 0 && (b == 0 || s.back() != 'b')) {
                s += 'a';
                a--;
            } else {
                s += 'b';
                b--;
            }
        }
        return s;
    }
};
```
